const input = $input.item.json;
const messages = [];

messages.push({
  role: "system",
  content: `You are an assistant that extracts stock or crypto tickers if they exist.

Return VALID JSON ONLY in this format:
{
  "text": string,
  "ticker": string | null
}

Rules:
- Use standard tickers (AAPL, TSLA, BTCUSDT, SPX)
- If no ticker is clearly mentioned or implied, set ticker to null
- Do not invent tickers
- No markdown code blocks
- No backticks
- Raw JSON only`
});

if (Array.isArray(input.history)) {
  for (const msg of input.history) {
    if (msg.role && msg.content) {
      messages.push({ role: msg.role, content: msg.content });
    }
  }
}

const userMessage = input.message || input.body?.message || "";
if (userMessage.trim()) {
  messages.push({ role: "user", content: userMessage });
}

return { 
  session_id: input.session_id || input.body?.session_id || "default-session", 
  messages 
};

const response = $input.item.json;

let content = response.choices?.[0]?.message?.content || "";

content = content
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .replace(/^`+|`+$/g, '')
  .trim();

const jsonMatch = content.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  content = jsonMatch[0];
}

let parsed;
try {
  parsed = JSON.parse(content);
} catch (error) {
  content = content.replace(/[\r\n]+/g, ' ');
  try {
    parsed = JSON.parse(content);
  } catch (e) {
    throw new Error(`Failed to parse JSON: ${content}`);
  }
}

const sessionId = $('Prepare Prompt').item.json.session_id;

return {
  session_id: sessionId,
  text: parsed.text || "",
  ticker: parsed.ticker || null
};

const ticker = $input.item.json.ticker;
const text = $input.item.json.text;
const sessionId = $input.item.json.session_id;

// Generate a simple chart URL using QuickChart
const chartConfig = {
  type: 'line',
  data: {
    labels: ['5d ago', '4d ago', '3d ago', '2d ago', 'Yesterday', 'Today'],
    datasets: [{
      label: ticker + ' Price Trend',
      data: [100, 102, 101, 105, 107, 110],
      borderColor: 'rgb(34, 139, 34)',
      backgroundColor: 'rgba(34, 139, 34, 0.1)',
      fill: true,
      tension: 0.4,
      pointRadius: 4,
      pointHoverRadius: 6
    }]
  },
  options: {
    title: {
      display: true,
      text: ticker + ' - Price Chart',
      fontSize: 18,
      fontColor: '#333'
    },
    legend: {
      display: false
    },
    scales: {
      yAxes: [{
        ticks: {
          callback: function(value) {
            return '$' + value;
          }
        },
        gridLines: {
          color: 'rgba(0, 0, 0, 0.1)'
        }
      }],
      xAxes: [{
        gridLines: {
          display: false
        }
      }]
    }
  }
};

// Generate chart URL
const chartUrl = `https://quickchart.io/chart?width=600&height=300&backgroundColor=white&c=${encodeURIComponent(JSON.stringify(chartConfig))}`;

// Alternative chart services you can use:
// TradingView: https://www.tradingview.com/chart/?symbol=${ticker}
// FinViz: https://finviz.com/chart.ashx?t=${ticker}&ty=c&ta=1&p=d

return {
  session_id: sessionId,
  text: text,
  ticker: ticker,
  chart_url: chartUrl,
  chart_embed: `<img src="${chartUrl}" alt="${ticker} chart" />`,
  tradingview_link: `https://www.tradingview.com/chart/?symbol=${ticker}`
};

const sessionId = $input.item.json.session_id;
const text = $input.item.json.text;

return {
  session_id: sessionId,
  text: text,
  ticker: null,
  chart_url: null,
  tradingview_link: null
};
